const { redis } = require('../config/database');

class SocketManager {
  constructor(io) {
    this.io = io;
    this.rooms = new Map(); // 房间管理
    this.userSockets = new Map(); // 用户socket映射
    this.connectionStats = {
      totalConnections: 0,
      activeConnections: 0,
      peakConnections: 0
    };
    
    this.setupEventHandlers();
    this.startHealthCheck();
  }

  // 设置事件处理器
  setupEventHandlers() {
    this.io.on('connection', (socket) => {
      this.handleConnection(socket);
    });
  }

  // 处理新连接
  async handleConnection(socket) {
    try {
      this.connectionStats.totalConnections++;
      this.connectionStats.activeConnections++;
      this.connectionStats.peakConnections = Math.max(
        this.connectionStats.peakConnections,
        this.connectionStats.activeConnections
      );

      console.log(`🔌 WebSocket连接: ${socket.id} (活跃连接: ${this.connectionStats.activeConnections})`);

      // 设置连接超时
      socket.conn.on('packet', ({ type, data }) => {
        if (type === 'pong') {
          socket.lastPong = Date.now();
        }
      });

      // 用户认证
      socket.on('authenticate', async (data) => {
        await this.handleAuthentication(socket, data);
      });

      // 加入房间
      socket.on('joinRoom', (roomId) => {
        this.joinRoom(socket, roomId);
      });

      // 离开房间
      socket.on('leaveRoom', (roomId) => {
        this.leaveRoom(socket, roomId);
      });

      // 像素更新
      socket.on('pixelUpdate', (data) => {
        this.handlePixelUpdate(socket, data);
      });

      // 心跳检测
      socket.on('ping', () => {
        socket.emit('pong', { timestamp: Date.now() });
      });

      // 断开连接
      socket.on('disconnect', (reason) => {
        this.handleDisconnection(socket, reason);
      });

      // 错误处理
      socket.on('error', (error) => {
        console.error(`WebSocket错误 (${socket.id}):`, error);
      });

    } catch (error) {
      console.error('处理WebSocket连接时出错:', error);
      socket.disconnect(true);
    }
  }

  // 处理用户认证
  async handleAuthentication(socket, data) {
    try {
      const { token, userId } = data;
      
      if (!token || !userId) {
        socket.emit('authError', { message: '认证信息不完整' });
        return;
      }

      // 验证JWT token
      const jwt = require('jsonwebtoken');
      const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';
      
      try {
        const decoded = jwt.verify(token, JWT_SECRET);
        
        // 验证用户ID是否匹配
        if (decoded.id !== userId) {
          socket.emit('authError', { message: '用户ID不匹配' });
          return;
        }

        // 检查token是否过期
        if (decoded.exp && Date.now() >= decoded.exp * 1000) {
          socket.emit('authError', { message: 'Token已过期' });
          return;
        }

        // 验证用户是否存在
        const User = require('../models/User');
        const user = await User.findById(userId);
        if (!user) {
          socket.emit('authError', { message: '用户不存在' });
          return;
        }

        // 设置socket认证状态
        socket.userId = userId;
        socket.authenticated = true;
        socket.userRole = user.role || 'user';
        socket.lastActivity = Date.now();

        // 记录用户socket映射
        if (!this.userSockets.has(userId)) {
          this.userSockets.set(userId, new Set());
        }
        this.userSockets.get(userId).add(socket);

        // 加入用户房间
        socket.join(`user:${userId}`);

        // 记录认证日志
        console.log(`✅ WebSocket认证成功: ${userId} (socket: ${socket.id}, role: ${user.role})`);

        // 发送认证成功
        socket.emit('authenticated', { 
          userId,
          role: user.role,
          timestamp: Date.now()
        });

      } catch (jwtError) {
        console.error('JWT验证失败:', jwtError);
        socket.emit('authError', { message: 'Token验证失败' });
        return;
      }

    } catch (error) {
      console.error('WebSocket认证失败:', error);
      socket.emit('authError', { message: '认证失败' });
    }
  }

  // 加入房间
  joinRoom(socket, roomId) {
    if (!socket.authenticated) {
      socket.emit('error', { message: '请先认证' });
      return;
    }

    socket.join(roomId);
    
    if (!this.rooms.has(roomId)) {
      this.rooms.set(roomId, new Set());
    }
    this.rooms.get(roomId).add(socket.id);

    socket.emit('roomJoined', { roomId });
    console.log(`🏠 用户 ${socket.userId} 加入房间: ${roomId}`);
  }

  // 离开房间
  leaveRoom(socket, roomId) {
    socket.leave(roomId);
    
    if (this.rooms.has(roomId)) {
      this.rooms.get(roomId).delete(socket.id);
      if (this.rooms.get(roomId).size === 0) {
        this.rooms.delete(roomId);
      }
    }

    socket.emit('roomLeft', { roomId });
    console.log(`🚪 用户 ${socket.userId} 离开房间: ${roomId}`);
  }

  // 处理像素更新
  handlePixelUpdate(socket, data) {
    if (!socket.authenticated) {
      socket.emit('error', { message: '请先认证' });
      return;
    }

    // 广播给所有客户端（除了发送者）
    socket.broadcast.emit('pixelUpdate', {
      ...data,
      userId: socket.userId,
      timestamp: Date.now()
    });
  }

  // 处理断开连接
  handleDisconnection(socket, reason) {
    this.connectionStats.activeConnections--;

    // 清理用户socket映射
    if (socket.userId && this.userSockets.has(socket.userId)) {
      this.userSockets.get(socket.userId).delete(socket);
      if (this.userSockets.get(socket.userId).size === 0) {
        this.userSockets.delete(socket.userId);
      }
    }

    // 清理房间
    for (const [roomId, sockets] of this.rooms.entries()) {
      sockets.delete(socket.id);
      if (sockets.size === 0) {
        this.rooms.delete(roomId);
      }
    }

    console.log(`🔌 WebSocket断开: ${socket.id} (原因: ${reason}, 活跃连接: ${this.connectionStats.activeConnections})`);
  }

  // 广播消息到房间
  broadcastToRoom(roomId, event, data) {
    this.io.to(roomId).emit(event, data);
  }

  // 广播消息到用户
  broadcastToUser(userId, event, data) {
    this.io.to(`user:${userId}`).emit(event, data);
  }

  // 广播消息到所有用户
  broadcastToAll(event, data) {
    this.io.emit(event, data);
  }

  // 获取连接统计
  getConnectionStats() {
    return {
      ...this.connectionStats,
      rooms: this.rooms.size,
      authenticatedUsers: this.userSockets.size
    };
  }

  // 健康检查
  startHealthCheck() {
    setInterval(() => {
      const stats = this.getConnectionStats();
      console.log('📊 WebSocket统计:', stats);

      // 检查连接健康状态
      this.io.sockets.sockets.forEach((socket) => {
        if (socket.lastPong && Date.now() - socket.lastPong > 30000) {
          console.log(`⚠️ 检测到不活跃连接: ${socket.id}`);
          socket.disconnect(true);
        }
      });
    }, 30000); // 每30秒检查一次
  }

  // 优雅关闭
  async gracefulShutdown() {
    console.log('🔄 开始优雅关闭WebSocket服务...');
    
    // 通知所有客户端
    this.broadcastToAll('serverShutdown', { 
      message: '服务器即将关闭，请保存您的工作',
      timestamp: Date.now()
    });

    // 等待5秒让客户端处理
    await new Promise(resolve => setTimeout(resolve, 5000));

    // 关闭所有连接
    this.io.close(() => {
      console.log('✅ WebSocket服务已关闭');
    });
  }
}

module.exports = SocketManager;
